module top_module(
	input			clock,
	input			wren,
	input	[4:0]		wraddress,
	input	[4:0]		rdaddress,
	input	[8:0]		data,
	output	reg	[8:0]	q 
	);reg	[8:0]	obf_mem_a [0:31];

always @(posedge clock) if(wren) obf_mem_a[wraddress] <= data;

always @(posedge clock) q <= obf_mem_a[rdaddress];


endmodule
